{
  "query": "China A股 stock real-time price quote API",
  "total": 5,
  "results": [
    {
      "tool_id": "finnhub_io_api.stock.quote",
      "name": "Quote",
      "description": "Get real-time quote data for US stocks.",
      "params": [
        {
          "name": "symbol",
          "type": "string",
          "required": true,
          "description": "Stock symbol"
        }
      ],
      "examples": {
        "sample_parameters": {
          "symbol": "AAPL"
        }
      },
      "provider_description": "Finnhub - Free APIs for realtime stock, forex, and cryptocurrency. Company fundamentals, Economic data, and Alternative data.",
      "stats": {
        "avg_execution_time_ms": 853.46,
        "success_rate": 0.951
      }
    },
    {
      "tool_id": "ths_ifind.real_time_quotation.v1",
      "name": "iFinD 同花顺实时行情 (THS Real-time Quotation)",
      "description": "Query real-time quotation data for securities in the 同花顺 (THS) iFinD database, providing real-time market data for financial products including stocks, funds, bonds, and futures, such as real-time prices, trading volumes, price changes, bid/ask quotes, etc. Supports querying various real-time indicators including latest price, price change, trading volume, turnover ratio, market value, and five-level bid/ask quotes.",
      "params": [
        {
          "name": "codes",
          "type": "string",
          "required": true,
          "description": "Security codes, multiple codes separated by commas (max 50), e.g., '300033.SZ,600030.SH'"
        },
        {
          "name": "indicators",
          "type": "string",
          "required": false,
          "description": "Indicator list, multiple indicators separated by commas. Options: 'common' (common indicators), 'all' (all indicators), or custom indicator list. Default is 'all'"
        }
      ],
      "examples": {
        "sample_parameters": {
          "codes": "300033.SZ,600030.SH"
        }
      },
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 1667.64,
        "success_rate": 0.887
      }
    },
    {
      "tool_id": "eodhd.live_prices.retrieve.v1.178541d4",
      "name": "Live (Delayed) Stock Prices",
      "description": "Retrieve live or delayed stock prices and macroeconomic data.",
      "params": [
        {
          "name": "ticker",
          "type": "string",
          "required": true,
          "description": {
            "en": "Ticker symbol with exchange suffix (e.g., AAPL.US)."
          }
        },
        {
          "name": "s",
          "type": "string",
          "required": false,
          "description": {
            "en": "Optional filter parameter."
          }
        }
      ],
      "examples": {
        "sample_parameters": {
          "ticker": "AAPL.US"
        }
      },
      "provider_description": "Access historical end-of-day stock prices, intraday data, US stock options, and real-time prices with free and advanced plans. EODHD provides financial data for 150,000+ tickers, including stocks, ETFs, funds, and currencies worldwide.",
      "stats": {
        "avg_execution_time_ms": 1207.16,
        "success_rate": 0.946
      }
    },
    {
      "tool_id": "twelvedata.quote.retrieve.v1.affbefe3",
      "name": "Quote",
      "description": "The quote endpoint provides real-time data for a selected financial instrument, returning essential information such as the latest price, open, high, low, close, volume, and price change. This endpoint is ideal for users needing up-to-date market data to track price movements and trading activity for specific stocks, ETFs, or other securities.",
      "params": [
        {
          "name": "symbol",
          "type": "string",
          "required": false,
          "description": {
            "en": "Symbol ticker of the instrument"
          }
        },
        {
          "name": "figi",
          "type": "string",
          "required": false,
          "description": {
            "en": "Filter by financial instrument global identifier (FIGI). This request parameter is available starting with the <a href=\"https://twelvedata.com/pricing\">Ultra<a> plan"
          }
        },
        {
          "name": "isin",
          "type": "string",
          "required": false,
          "description": {
            "en": "Filter by international securities identification number (ISIN). ISIN access is activating in the <a href=\"https://twelvedata.com/account/add-ons\">Data add-ons</a> section"
          }
        },
        {
          "name": "cusip",
          "type": "string",
          "required": false,
          "description": {
            "en": "The CUSIP of an instrument for which data is requested. CUSIP access is activating in the <a href=\"https://twelvedata.com/account/add-ons\">Data add-ons</a> section"
          }
        },
        {
          "name": "interval",
          "type": "string",
          "required": false,
          "description": {
            "en": "Interval of the quote"
          },
          "enum": [
            "1min",
            "5min",
            "15min",
            "30min",
            "45min",
            "1h",
            "2h",
            "4h",
            "1day",
            "1week",
            "1month"
          ]
        },
        {
          "name": "exchange",
          "type": "string",
          "required": false,
          "description": {
            "en": "Exchange where instrument is traded"
          }
        },
        {
          "name": "mic_code",
          "type": "string",
          "required": false,
          "description": {
            "en": "Market Identifier Code (MIC) under ISO 10383 standard"
          }
        },
        {
          "name": "country",
          "type": "string",
          "required": false,
          "description": {
            "en": "Country where instrument is traded, e.g., `United States` or `US`"
          }
        },
        {
          "name": "volume_time_period",
          "type": "integer",
          "required": false,
          "description": {
            "en": "Number of periods for Average Volume"
          }
        },
        {
          "name": "type",
          "type": "string",
          "required": false,
          "description": {
            "en": "The asset class to which the instrument belongs"
          },
          "enum": [
            "American Depositary Receipt",
            "Bond",
            "Bond Fund",
            "Closed-end Fund",
            "Common Stock",
            "Depositary Receipt",
            "Digital Currency",
            "ETF",
            "Exchange-Traded Note",
            "Global Depositary Receipt",
            "Limited Partnership",
            "Mutual Fund",
            "Physical Currency",
            "Preferred Stock",
            "REIT",
            "Right",
            "Structured Product",
            "Trust",
            "Unit",
            "Warrant"
          ]
        },
        {
          "name": "format",
          "type": "string",
          "required": false,
          "description": {
            "en": "Value can be JSON or CSV\nDefault JSON"
          },
          "enum": [
            "JSON",
            "CSV"
          ]
        },
        {
          "name": "delimiter",
          "type": "string",
          "required": false,
          "description": {
            "en": "Specify the delimiter used when downloading the CSV file"
          }
        },
        {
          "name": "prepost",
          "type": "boolean",
          "required": false,
          "description": {
            "en": "Parameter is optional. Only for `Pro` and above plans.\nAvailable at the `1min`, `5min`, `15min`, and `30min` intervals for US equities.\nOpen, high, low, close values are supplied without volume."
          }
        },
        {
          "name": "eod",
          "type": "boolean",
          "required": false,
          "description": {
            "en": "If true, then return data for closed day"
          }
        },
        {
          "name": "rolling_period",
          "type": "integer",
          "required": false,
          "description": {
            "en": "Number of hours for calculate rolling change at period. By default set to 24, it can be in range [1, 168]."
          }
        },
        {
          "name": "dp",
          "type": "integer",
          "required": false,
          "description": {
            "en": "Specifies the number of decimal places for floating values\nShould be in range [0,11] inclusive"
          }
        },
        {
          "name": "timezone",
          "type": "string",
          "required": false,
          "description": {
            "en": "Timezone at which output datetime will be displayed. Supports:\n<ul>\n<li>1. <code>Exchange</code> for local exchange time</li>\n<li>2. <code>UTC</code> for datetime at universal UTC standard</li>\n<li>3. Timezone name according to the IANA Time Zone Database. E.g. <code>America/New_York</code>, <code>Asia/Singapore</code>. Full list of timezones can be found <a href=\"https://en.wikipedia.org/wiki/List_of_tz_database_time_zones\" target=\"blank\">here</a>.</li>\n</ul>\n<i>Take note that the IANA Timezone name is case-sensitive</i>"
          }
        }
      ],
      "examples": {
        "sample_parameters": {
          "symbol": "AAPL"
        }
      },
      "provider_description": "Financial APIs providing real-time, historical, and EOD data for stocks, forex, cryptocurrency, ETFs, commodities, and fundamental market data. If the parameters of the tool include symbol, figi, isin, and cusip, one of these four parameters must be selected as a required parameter.",
      "stats": {
        "avg_execution_time_ms": 0.596,
        "success_rate": 1
      }
    },
    {
      "tool_id": "eodhd.real_time.retrieve.v1.3b8a5cf8",
      "name": "Retrieve Real-Time (Delayed) Stock Prices",
      "description": "Fetch real-time price data for a specified cryptocurrency pair.",
      "params": [
        {
          "name": "symbol",
          "type": "string",
          "required": true,
          "description": {
            "en": "Stock ticker symbol with exchange suffix (e.g., AAPL.US)"
          }
        },
        {
          "name": "fmt",
          "type": "string",
          "required": false,
          "description": {
            "en": "Response format"
          },
          "enum": [
            "json",
            "csv"
          ]
        }
      ],
      "examples": {
        "sample_parameters": {
          "symbol": "EUR.FOREX"
        }
      },
      "provider_description": "Access historical end-of-day stock prices, intraday data, US stock options, and real-time prices with free and advanced plans. EODHD provides financial data for 150,000+ tickers, including stocks, ETFs, funds, and currencies worldwide.",
      "stats": {
        "avg_execution_time_ms": 1093.58,
        "success_rate": 0.948
      }
    }
  ],
  "search_id": "98752c03-5c19-4135-bcfb-844dda3b4908",
  "elapsed_time_ms": 454.36
}

